// --- KOMPONENT KARTY WSKAŹNIKA ---
function IndicatorCard({ title, value, suffix, loading, color, description, impact }: any) {
  return (
    <div style={{ 
      background: '#FFF', 
      borderRadius: '24px', 
      padding: '24px', 
      boxShadow: '0 4px 20px rgba(0,0,0,0.03)', 
      display: 'flex', 
      flexDirection: 'column',
      justifyContent: 'space-between',
      height: '100%'
    }}>
      <div>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '8px' }}>
          <h3 style={{ fontSize: '0.9rem', fontWeight: 600, color: '#86868b', textTransform: 'uppercase', letterSpacing: '0.02em', margin: 0 }}>{title}</h3>
          <div style={{ background: `${color}15`, padding: '6px', borderRadius: '50%' }}>
            {title.includes("Inflacja") ? <TrendingUp size={16} color={color} /> : <Percent size={16} color={color} />}
          </div>
        </div>
        
        <div style={{ fontSize: '2.5rem', fontWeight: 700, color: '#1D1D1F', marginBottom: '16px', lineHeight: 1 }}>
          {loading ? (
            <span style={{ opacity: 0.2 }}>...</span>
          ) : (
            <span>{value?.toFixed(2)}<span style={{ fontSize: '1.25rem', color: '#86868b', marginLeft: '2px' }}>{suffix}</span></span>
          )}
        </div>
      </div>

      <div style={{ borderTop: '1px solid #f5f5f5', paddingTop: '16px' }}>
        <p style={{ fontSize: '0.85rem', color: '#1D1D1F', marginBottom: '8px', fontWeight: 500 }}>
          {description}
        </p>
        <div style={{ display: 'flex', gap: '8px', alignItems: 'flex-start' }}>
          <Info size={14} color="#86868b" style={{ marginTop: '3px', flexShrink: 0 }} />
          <p style={{ fontSize: '0.8rem', color: '#86868b', lineHeight: 1.4, margin: 0 }}>
            {impact}
          </p>
        </div>
      </div>
    </div>
  );
}